hudson.tasks.Shell.command:
#!/bin/bash # 鏋勫缓鎴愬姛鍚庣殑鐙珛姝ラ锛氭彁浜ゅ苟鎺ㄩ€佹湰鍦?Git 鍙樺姩鍒拌繙绔?echo "=======================================" echo " 姝ラ: 鎻愪氦骞舵帹閫佹湰鍦板彉鏇村埌杩滅" echo "=======================================" [ -n "$JENKINS_HOME" ] && [ -f "${JENKINS_HOME}/.apk-site-env" ] && . "${JENKINS_HOME}/.apk-site-env" if [ -z "$GIT_WORKSPACE" ] || [ ! -d "$GIT_WORKSPACE/.git" ]; then echo "璺宠繃: 鏈厤缃?GIT_WORKSPACE 鎴栭潪 Git 浠撳簱" else echo "Git 宸ヤ綔鐩綍: $GIT_WORKSPACE" if [ -n "$GIT_SSH_KEY_PATH" ] && [ -f "$GIT_SSH_KEY_PATH" ]; then export GIT_SSH_COMMAND="ssh -i $GIT_SSH_KEY_PATH -o StrictHostKeyChecking=no" fi (cd "$GIT_WORKSPACE" && \ if [ -n "$(git status --porcelain)" ]; then \ echo "鍙戠幇鏈彁浜ゅ彉鏇达紝鎵ц add/commit/push"; \ git add -A && \ git -c user.email="jenkins@apk-site.local" -c user.name="Jenkins Builder" commit -m "Jenkins 鏋勫缓 #${BUILD_NUMBER:-?} 鑷姩鎻愪氦 (${APP_NAME:-build} ${VERSION_NAME:-})" && \ (git push origin HEAD 2>&1 && echo "鉁?宸叉帹閫佸埌杩滅") || echo "鈿?鎺ㄩ€佸け璐?quot;; \ else \ echo "鏃犳湭鎻愪氦鍙樻洿"; \ (git push origin HEAD 2>&1 && echo "鉁?宸叉帹閫佸凡鏈夋彁浜?quot;) || echo "鈿?鏃犲彲鎺ㄩ€佹垨鎺ㄩ€佸け璐?quot;; \ fi) || echo "鈿?Git 鎻愪氦/鎺ㄩ€佸凡璺宠繃" echo "Git 鎻愪氦涓庢帹閫佹楠ょ粨鏉?quot; fi echo "" echo "=== 鏇存柊 Jenkins 鍙傛暟榛樿鍊?===" bash ~/update_jenkins_params.sh || echo "鍙傛暟鏇存柊澶辫触锛堜笉褰卞搷鏋勫缓缁撴灉锛?quot; echo "璋冪敤閫氱煡鑴氭湰..." [ -n "$JENKINS_HOME" ] && [ -f "${JENKINS_HOME}/.apk-site-env" ] && . "${JENKINS_HOME}/.apk-site-env" SCRIPT_DIR="${JENKINS_CLONE:-$JENKINS_HOME}/scripts" [ -n "$JENKINS_HOME" ] && [ -f "${JENKINS_HOME}/.apk-site-env" ] && . "${JENKINS_HOME}/.apk-site-env" [ -n "$JENKINS_HOME" ] && [ -f "${JENKINS_HOME}/.apk-site-dingtalk" ] && . "${JENKINS_HOME}/.apk-site-dingtalk" SCRIPT_DIR="${JENKINS_CLONE:-$JENKINS_HOME}/scripts" # 椋炰功閫氱煡 [ -d "$SCRIPT_DIR" ] && "${SCRIPT_DIR}/jenkins_send_notify.sh" "${VERSION_NAME}" "${BUILD_NUMBER}" || echo "椋炰功閫氱煡鍙戦€佸け璐? # 閽夐拤閫氱煡 if [ -n "$DINGTALK_WEBHOOK" ] && [ -d "$SCRIPT_DIR" ]; then python3 -c " import json, urllib.request msg = {'msgtype': 'markdown', 'markdown': {'title': 'Jenkins 鏋勫缓閫氱煡', 'text': f'## 馃摝 Jenkins 鏋勫缓瀹屾垚

- **鐗堟湰**: ${VERSION_NAME}
- **鏋勫缓鍙?*: #${BUILD_NUMBER}
- **搴旂敤**: ${APP_NAME}
- **鐘舵€?*: 瀹屾垚
'}} req = urllib.request.Request('${DINGTALK_WEBHOOK}', data=json.dumps(msg).encode(), headers={'Content-Type': 'application/json'}) try: urllib.request.urlopen(req); print('閽夐拤閫氱煡宸插彂閫?) except Exception as e: print(f'閽夐拤閫氱煡澶辫触: {e}') " 2>/dev/null || echo "閽夐拤閫氱煡鍙戦€佸け璐? fi
